module full_adder(
    input A,
    input B,
    input CIN,
    output SUM,
    output COUT
);

wire unused_w1, w2, w3;

// Calculate SUM
assign unused_w1 = A ^ B;
assign SUM = unused_w1 ^ CIN;

// Calculate COUT
assign w2 = A & B;
assign w3 = CIN & unused_w1;
assign COUT = w2 | w3;

endmodule
